rules.regoSource:
import rego.v1

score_entry["freeleech_bonus"] := 500 if {
    input.release.extra.freeleech == true
}

import rego.v1

score_entry["well_seeded"] := 200 if {
    input.release.extra.seeders >= 10
}

score_entry["poorly_seeded"] := -300 if {
    input.release.extra.seeders != null
    input.release.extra.seeders < 3
}

import rego.v1

score_entry["dead_torrent"] := scryer.block_score() if {
    input.release.extra.seeders == 0
}

import rego.v1

score_entry["internal_bonus"] := 300 if {
    some tag in input.release.extra.tags
    lower(tag) == "internal"
}
